#[cfg(test)]
mod checkpoint_tests {
    #[test]
    fn checkpoint_resets_progress_timer() {
        init_deadline_test_logging();

        let lab = LabRuntimeBuilder::new().rng_seed(42).build();

        lab.run_with_cx(|cx| async move {
            let budget = Budget::deadline(Duration::from_secs(10))
                .with_checkpoint_interval(Duration::from_millis(100));

            cx.with_budget(budget, async {
                for i in 0..5 {
                    // Each checkpoint resets the interval
                    cx.checkpoint();
                    sleep(Duration::from_millis(50)).await;
                    tracing::debug!(iteration = %i, "Checkpoint issued");
                }
            }).await;

            tracing::info!("All checkpoints issued without warning");
        });
    }

