```rust
#[test]
fn e2e_stuck_task_detection() {
    init_deadline_test_logging();

    tracing::info!("═══════════════════════════════════════════");
    tracing::info!("E2E: Stuck Task Detection Workflow");
    tracing::info!("═══════════════════════════════════════════");

    let detected_stuck = Arc::new(AtomicBool::new(false));
    let detected_stuck2 = detected_stuck.clone();

    let monitor = DeadlineMonitor {
        warning_threshold: Duration::from_millis(50),
        on_warning: Box::new(move |warning| {
            tracing::warn!(
                task_id = ?warning.task_id,
                remaining = ?warning.remaining,
                last_checkpoint = ?warning.last_checkpoint_message,
                "⚠️  DEADLINE WARNING: Task appears stuck!"
            );
            detected_stuck2.store(true, Ordering::SeqCst);
        }),
    };

    let lab = LabRuntimeBuilder::new()
        .rng_seed(42)
        .deadline_monitor(monitor)
        .build();

    lab.run_with_cx(|cx| async move {
        let budget = Budget::deadline(Duration::from_secs(1))
            .with_checkpoint_interval(Duration::from_millis(50));

        let _ = cx.with_budget(budget, async {
            // Simulate a task that gets stuck
            cx.checkpoint_with("Starting batch processing");

            // This simulates an I/O operation that hangs
            tracing::debug!("Simulating stuck I/O...");
            sleep(Duration::from_millis(200)).await;

        }).await;
    });

    assert!(detected_stuck.load(Ordering::SeqCst), "Should have detected stuck task");
    tracing::info!("E2E stuck task detection completed");
}
